    public String convertYamlToJSON(String content) throws JsonProcessingException {
        ObjectMapper yamlReader = new ObjectMapper(new YAMLFactory());
        Object obj = yamlReader.readValue(content, Object.class);
        ObjectMapper jsonWriter = new ObjectMapper();
        try {
            return jsonWriter.writeValueAsString(obj);
        } catch (JsonProcessingException e) {
            log.error(e.getMessage());
            return "";
        }
    }

    public String convertJSONToYAML(String content) throws JsonProcessingException {
        JsonNode jsonNodeTree = new ObjectMapper().readTree(content);
        return new YAMLMapper().writeValueAsString(jsonNodeTree);
    }

    public ConcurrentHashMap<String, Object> execCmd(String[] cmd) {
        ProcessBuilder processBuilder = new ProcessBuilder(cmd);
        ConcurrentHashMap<String, Object> concurrentHashMap = new ConcurrentHashMap<>();
        try {
            Process process = processBuilder.start();
            try (BufferedReader stdIn = new BufferedReader(new InputStreamReader(process.getInputStream()))) {
                concurrentHashMap.put("result", stdIn.lines().collect(Collectors.joining("\n")));
            }
            try (BufferedReader stdErr = new BufferedReader(new InputStreamReader(process.getErrorStream()))) {
                concurrentHashMap.put("error", stdErr.lines().collect(Collectors.joining("\n")));
            }
            if (concurrentHashMap.get("error") != null && concurrentHashMap.get("error").toString().length() > 0) {
                concurrentHashMap.put("success", false);
            } else {
                concurrentHashMap.put("success", true);
            }
            return concurrentHashMap;
        } catch (Exception e) {
            log.error(e.getMessage());
            concurrentHashMap.put("success", false);
            return concurrentHashMap;
        }
    }

    public HashMap<String, String> execPipedCmd(String[] cmd) {
        String result = "";
        String error = "";
        HashMap<String, String> output = new HashMap<>();
        try {
            Process p = Runtime.getRuntime().exec(cmd);
            BufferedReader stdIn = new BufferedReader(new InputStreamReader(p.getInputStream()));
            BufferedReader stdErr = new BufferedReader(new InputStreamReader(p.getErrorStream()));
            String inputLine;
            String errorLine;
            while ((inputLine = stdIn.readLine()) != null) {
                result += inputLine;
            }
            while ((errorLine = stdErr.readLine()) != null) {
                error += errorLine;
            }
            stdErr.close();
            stdIn.close();
            if (error.length() > 1) {
                throw new Exception(error);
            } else {
                output.put("output", result);
                output.put("status", "true");
            }
        } catch (Exception e) {
//            System.out.println("****************************************************************************************");
            log.error(e.getMessage());
//            System.out.println("****************************************************************************************");
            output.put("output", "");
            output.put("status", "false");
        }
        return output;
    }

