    public NetworkConditionsResponseDTO createGuestDockerNetwork(DockerDTO network) {
        try {
            log.info("Docker DTO inside createGuestDockerNetwork Function is : {}", network);
            String subnet = networkUtils.generateSubnetFromIpAndCidr(network.getExternal_ip_address(), network.getCidr());
            log.info("{} subnet", subnet);
            String macvlan_name = this.generateMacvlanName(network.getInterface_out(), network.getVlan_id());
            if (network.getGateway() != null && network.getGateway().length() > 1) {
                if (network.getVlan_id() != null) {
                    log.info("Creating macvlan with gateway and vlan id");
                    return dockerUtils.createMacVlan(new NetworkDTO(macvlan_name, "macvlan", subnet, network.getGateway(), network.getInterface_out() + "." + network.getVlan_id()), network.getNetwork_origin());
                } else {
                    log.info("Creating macvlan with gateway and without vlan id");
                    return dockerUtils.createMacVlan(new NetworkDTO(macvlan_name, "macvlan", subnet, network.getGateway(), network.getInterface_out()), network.getNetwork_origin());
                }
            } else {
                if (network.getVlan_id() != null) {
                    log.info("Creating macvlan without gateway and with vlan id");
                    return dockerUtils.createMacVlan(new NetworkDTO(macvlan_name, "macvlan", subnet, null, network.getInterface_out() + "." + network.getVlan_id()), network.getNetwork_origin());
                } else {
                    log.info("Creating macvlan without gateway and without vlan id");
                    return dockerUtils.createMacVlan(new NetworkDTO(macvlan_name, "macvlan", subnet, null, network.getInterface_out()), network.getNetwork_origin());
                }
            }
        } catch (Exception e) {
            log.error(e.getMessage(), e);
            return new NetworkConditionsResponseDTO(e.getMessage(), HttpStatus.INTERNAL_SERVER_ERROR, false);
        }
    }

