    public NetworkConditionsResponseDTO deleteGuestDocker(String name, String macvlan_name, Integer network_origin) {
        boolean isContainerPresent;
        boolean isNetworkPresent;
        if (network_origin == 0) {
            isContainerPresent = false /* stubbed: masterSlaveAPICallService removed (Bucket D) */;
        } else {
            isContainerPresent = false /* stubbed: restartNetworkService removed (Bucket D) */;
        }
        if (network_origin == 0) {
            isNetworkPresent = false /* stubbed: masterSlaveAPICallService removed (Bucket D) */;
        } else {
            isNetworkPresent = false /* stubbed: restartNetworkService removed (Bucket D) */;
        }
        // If container and network is already deleted return true
        // If network is not deleted but container is deleted run one command
        // If network and container both are not deleted run both commands
        // NOTE: Here true means NOT Exists & false means Exists (therefore adding negation signs in the below logs)
        log.info("Is container present : {}", !isContainerPresent);
        log.info("Is network present : {}", !isNetworkPresent);
        log.info("Network Origin is : {}", network_origin);
        if (isContainerPresent && isNetworkPresent) {
            log.info("Condition 1 met - Container NOT PRESENT & Network NOT PRESENT");
            return new NetworkConditionsResponseDTO("Provided network does not exist.", HttpStatus.OK, true);
        } else if (isContainerPresent && !isNetworkPresent) {
            log.info("Condition 2 met - Container NOT PRESENT & Network PRESENT");
            return dockerUtils.deleteMacVlan(macvlan_name, network_origin);
        } else if (!isContainerPresent && isNetworkPresent) {
            log.info("Condition 3 met - Container PRESENT & Network NOT PRESENT");
            return dockerUtils.deleteNetwork(name, network_origin);
        } else if (!isContainerPresent && !isNetworkPresent) {
            log.info("Condition 4 met - Container PRESENT & Network PRESENT");
            NetworkConditionsResponseDTO deleteNetworkStatus = dockerUtils.deleteNetwork(name, network_origin);
            if (!deleteNetworkStatus.getSuccess()) {
                return deleteNetworkStatus;
            }
            NetworkConditionsResponseDTO deleteMacVlanStatus = dockerUtils.deleteMacVlan(macvlan_name, network_origin);
            if (!deleteMacVlanStatus.getSuccess()) {
                return deleteMacVlanStatus;
            }
            return new NetworkConditionsResponseDTO("Network and MacVlan deleted successfully", HttpStatus.OK, true);
        }
        return new NetworkConditionsResponseDTO("message(true)", HttpStatus.OK, true);
    }

