    public String extractLastFourDigitsAndConvertToLowercase(String macAddress) {
        // Remove any non-hexadecimal characters from the MAC address
        macAddress = macAddress.replaceAll("[^a-fA-F0-9]", "");
        // Check if the MAC address is at least 4 characters long
        if (macAddress.length() < 4) {
            throw new IllegalArgumentException("Invalid MAC address");
        }
        // Extract the last 4 characters (digits) of the MAC address
        String lastFourDigits = macAddress.substring(macAddress.length() - 4);
        // Convert the last four digits to lowercase
        lastFourDigits = lastFourDigits.toLowerCase();
        return lastFourDigits;
    }

