    public BigInteger generateTimestampOfStartOftheDay(String timezone, String formatted_date) {
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("MMMM dd, yyyy", Locale.ENGLISH);
        LocalDate date = LocalDate.parse(formatted_date, formatter);
        ZoneId zoneId = ZoneId.of(timezone);
        ZonedDateTime zonedDateTime = date.atStartOfDay(zoneId);
        long timestamp = zonedDateTime.toInstant().toEpochMilli();
        return BigInteger.valueOf(timestamp);
    }

