    public Map<String, String> getSystemTimeZoneAlternate() throws IOException, InterruptedException {
        String script = "timezones=$(timedatectl list-timezones)\n" + "for zone in $timezones; do\n" + "  offset=$(TZ=$zone date +%:z)\n" + "  echo \"$zone (UTC$offset)\"\n" + "done\n";
        String output = executeScript(script);
        return convertToKeyValuePairs(output);
    }

    public String executeScript(String script) throws IOException, InterruptedException {
        String[] scriptArray = {"/bin/bash", "-c", script};
        Process process = Runtime.getRuntime().exec(scriptArray);
        StringBuilder timezones = new StringBuilder();
        try {
            BufferedReader bufferedReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = bufferedReader.readLine()) != null) {
                timezones.append(line).append("\n");
            }
        } catch (Exception e) {
            log.error(e.getMessage());
        }
        if (process.waitFor() != 0) {
            throw new RuntimeException("error executing the script...");
        }
        return timezones.toString();
    }

    //convert to key and value pairs
    public TreeMap<String, String> convertToKeyValuePairs(String output) {
        TreeMap<String, String> keyValuePairs = new TreeMap<>();
        String[] timezoneAndOffsets = output.split("\n");
        for (String timezoneAndOffset : timezoneAndOffsets) {
            String[] keyAndValue = timezoneAndOffset.split(" ", 2);
            keyValuePairs.put(keyAndValue[0], keyAndValue[1]);
        }
        return keyValuePairs;
    }

