    public String getPercentage(Integer current_value, Integer min_value, Integer max_value) {
        Integer percentage = ((current_value - min_value) * 100) / (max_value - min_value);
        if (percentage > 100) percentage = 100;
        if (percentage < 0) percentage = 0;
        return percentage.toString();
    }

    public static BigInteger getMaxTimeStamp(BigInteger t1, BigInteger t2) {
        if (t1 == null && t2 == null) {
            return null; // Both are null
        }
        if (t1 == null) {
            return t2; // t1 is null, return t2
        }
        if (t2 == null) {
            return t1; // t2 is null, return t1
        }
        return t1.max(t2); // Both are non-null, return the maximum
    }

    public static boolean isLessThan10Minutes(BigInteger timestamp) {
        // Get the current time in milliseconds
        long currentTimeMillis = Instant.now().toEpochMilli();
        // Convert BigInteger timestamp to long
        long timestampMillis = timestamp.longValue();
        // Calculate the duration
        Duration duration = Duration.ofMillis(currentTimeMillis - timestampMillis);
        return duration.toMinutes() < 10; // Check if duration is less than 5 minutes
    }

