    public void deleteFilesFromServer(String directory, Set<String> fileNames) {
        for (String fileName : fileNames) {
            log.info("File name: {}", fileName);
            Path filePath = Paths.get(directory, fileName);
            try {
                if (Files.exists(filePath)) {
                    Files.delete(filePath);
                    log.info("Removed {}", fileName);
                } else {
                    log.info("{} does not exist in the directory.", fileName);
                }
            } catch (IOException e) {
                log.info("Error removing {} : {}", fileName, e.getMessage());
            }
        }
    }

