    public HashMap<String, String> commandline(String cmd) {
        String[] cmd1 = new String[] {"bash", "-c", cmd};
        String result = "";
        String error = "";
        HashMap<String, String> output = new HashMap();
        try {
            Process p = Runtime.getRuntime().exec(cmd1);
            BufferedReader stdIn = new BufferedReader(new InputStreamReader(p.getInputStream()));
            BufferedReader stdErr = new BufferedReader(new InputStreamReader(p.getErrorStream()));
//            result = (String)stdIn.lines().collect(Collectors.joining("\n"));
            result =  // Append "\\n" as a string after each line
            stdIn.lines().map(line -> line + " \\n ").collect(Collectors.joining());
            log.info("result--------------------------- {}", result);
//            error = (String)stdErr.lines().collect(Collectors.joining("\n"));
            error = stdErr.lines().collect(Collectors.joining(" \\n "));
            stdErr.close();
            stdIn.close();
            if (error.length() > 1) {
                throw new Exception(error);
            }
            output.put("output", result);
            output.put("status", "true");
        } catch (Exception var11) {
//            System.out.println("*************************Catch***************************************************************");
            log.info(var11.getMessage());
//            System.out.println("****************************************************************************************");
            output.put("output", "");
            output.put("status", "false");
        }
        return output;
    }

